INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use a numbered lesson title that previews the learning outcome. Follow the module-specific pattern. Example: \"3. Routing — Building multi-page apps with Next.js\""},"content":{"tips":"Write for a learner progressing sequentially. Start with objectives, build incrementally, and end with a summary and next steps. Reference previous lessons when building on them."},"formatting":["Headings: Learning Objectives, Prerequisites, main topic sections, Summary, Exercises","Code blocks: all code samples with language tags and inline comments","Numbered lists: sequential steps, procedures, exercise instructions","Bullet lists: learning objectives, key takeaways, prerequisites","Tables: comparison of approaches, API reference within lessons","Blockquotes: tips, warnings, or important notes for learners"],"avoid":["Jumping between topics without clear transitions","Assuming knowledge not covered in prerequisite lessons","Code samples without explanation or context","Missing exercises or practice opportunities"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":200,"max":30000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

