INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('143a570d-5931-482c-8f6f-b7feeba6fb33', 'Enrollment Interest', 'enrollment-interest', 'Express interest in enrolling', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"experience_level","type":"select","label":"Experience Level","required":true,"options":["Beginner","Intermediate","Advanced"]},{"name":"goals","type":"textarea","label":"Learning Goals","required":true,"placeholder":"What do you hope to learn from this course?","maxLength":2000}]', '{"success_message":"Thanks for your interest! We''ll notify you when enrollment opens.","require_honeypot":true}', 'active', '2026-03-27T01:22:45.942Z', '2026-03-27T01:22:45.942Z');
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('d7c00349-8602-459f-8b3a-4810cbbeabd4', 'Feedback', 'feedback', 'Share feedback on the course material', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"rating","type":"select","label":"Overall Rating","required":true,"options":["1 - Poor","2 - Fair","3 - Good","4 - Very Good","5 - Excellent"]},{"name":"feedback","type":"textarea","label":"Your Feedback","required":true,"placeholder":"What worked well? What could be improved?","maxLength":2000}]', '{"success_message":"Thanks for the feedback! It helps us improve the course for everyone.","require_honeypot":true}', 'active', '2026-03-27T01:22:45.942Z', '2026-03-27T01:22:45.942Z');
